  ('fire-eq-tech-moex-02910', 'fire-eq-tech', 'fire-eq-tech-moex-098-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依照「防焰性能試驗基準」的規定，下列有關防焰物品或其材料之防焰性能規定，何者正確？', '["地毯等地坪舖設物類之餘焰時間不得超過30秒", "厚纖維製品餘燃時間不得超過20秒", "厚纖維製品碳化面積不得超過50平方公分", "具熱熔融性之纖維製品接焰次數應達2次以上"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:26+00:00", "source_pdf_sha1": "734519161faa", "answer_pdf_sha1": "253922401248", "source_family": "moex-gov-tw", "moex": {"exam_code": "098090", "c": "501", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "098", "exam_name": "098年專技高考引水人、驗船師考試、普考地政士、專責報關人員、保險代理人經紀人及公證人考試、98年第一次消防設備士考試、98年特考中醫師考試", "original_question_number": 21, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02911', 'fire-eq-tech', 'fire-eq-tech-moex-098-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依照「防焰性能認證實施要點」的規定，下列何者不是為「消防法」第11條所稱之防焰物品？', '["人工草皮與面積1.5平方公尺以上之門墊及地墊", "橫葉式百葉窗簾", "舞台或攝影棚使用之布幕", "網目在12公釐以下之施工用帆布"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:26+00:00", "source_pdf_sha1": "734519161faa", "answer_pdf_sha1": "253922401248", "source_family": "moex-gov-tw", "moex": {"exam_code": "098090", "c": "501", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "098", "exam_name": "098年專技高考引水人、驗船師考試、普考地政士、專責報關人員、保險代理人經紀人及公證人考試、98年第一次消防設備士考試、98年特考中醫師考試", "original_question_number": 22, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02912', 'fire-eq-tech', 'fire-eq-tech-moex-098-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依照「防焰性能認證實施要點」的規定，有關防焰性能試驗之產品試樣規格，下列規定何者正確？', '["須經水洗及乾洗處理之布幕，試樣規格為二平方公尺以上", "須經水洗或乾洗處理之窗簾，試樣規格為一平方公尺以上", "布製折屏試樣規格為一平方公尺以上", "施工用帆布試樣規格為二平方公尺以上"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:26+00:00", "source_pdf_sha1": "734519161faa", "answer_pdf_sha1": "253922401248", "source_family": "moex-gov-tw", "moex": {"exam_code": "098090", "c": "501", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "098", "exam_name": "098年專技高考引水人、驗船師考試、普考地政士、專責報關人員、保險代理人經紀人及公證人考試、98年第一次消防設備士考試、98年特考中醫師考試", "original_question_number": 23, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02913', 'fire-eq-tech', 'fire-eq-tech-moex-098-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依照「防焰性能認證實施要點」的規定，下列有關防焰合板之製造或其防焰性能加工處理業者規定之敘述， 何者有誤？', '["應設置使合板與表面材緊密貼合之防焰加工設備", "應設置寬90公分以上之浸泡容器及乾燥處理之防焰加工設備", "應設置調配防焰藥劑之器具", "應設置供分析欲施以合板防焰加工之布料材質"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:26+00:00", "source_pdf_sha1": "734519161faa", "answer_pdf_sha1": "253922401248", "source_family": "moex-gov-tw", "moex": {"exam_code": "098090", "c": "501", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "098", "exam_name": "098年專技高考引水人、驗船師考試、普考地政士、專責報關人員、保險代理人經紀人及公證人考試、98年第一次消防設備士考試、98年特考中醫師考試", "original_question_number": 24, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02914', 'fire-eq-tech', 'fire-eq-tech-moex-098-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依照「公共危險物品及可燃性高壓氣體設置標準暨安全管理辦法」的規定，六類危險物品製造或一般處理 場所四周保留空地寬度應在X公尺以上；儲存量達管制量10倍以上者，四周保留空地寬度應在Y公尺 以上，請問前述X，Y為何？', '["3，5", "5，8", "5，10", "4，6"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:26+00:00", "source_pdf_sha1": "734519161faa", "answer_pdf_sha1": "253922401248", "source_family": "moex-gov-tw", "moex": {"exam_code": "098090", "c": "501", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "098", "exam_name": "098年專技高考引水人、驗船師考試、普考地政士、專責報關人員、保險代理人經紀人及公證人考試、98年第一次消防設備士考試、98年特考中醫師考試", "original_question_number": 25, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02915', 'fire-eq-tech', 'fire-eq-tech-moex-098-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依照「公共危險物品及可燃性高壓氣體設置標準暨安全管理辦法」的規定，有關液化石油氣的販賣場所， 其液化石油氣備用量，供營業使用者，不得超過X公斤；供家庭使用者，不得超過Y公斤，請問前述X， Y為何？', '["100，50", "80，40", "70，35", "60，30"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:26+00:00", "source_pdf_sha1": "734519161faa", "answer_pdf_sha1": "253922401248", "source_family": "moex-gov-tw", "moex": {"exam_code": "098090", "c": "501", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "098", "exam_name": "098年專技高考引水人、驗船師考試、普考地政士、專責報關人員、保險代理人經紀人及公證人考試、98年第一次消防設備士考試、98年特考中醫師考試", "original_question_number": 26, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02916', 'fire-eq-tech', 'fire-eq-tech-moex-098-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依照「各類場所消防安全設備設置標準」的規定，某一棟建築物的各樓層均不屬於無開口樓層，且未設置 其他滅火設備，下列何種情形時，應依規定設置室內消防栓設備？', '["3層樓的建築物，任一層樓地板面積為200平方公尺之KTV場所", "4層樓的建築物，任一層樓地板面積為300平方公尺之辦公室場所", "7層樓的建築物，任一層樓地板面積200平方公尺之補習班場所", "總樓地板面積100平方公尺之地下建築物"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:26+00:00", "source_pdf_sha1": "734519161faa", "answer_pdf_sha1": "253922401248", "source_family": "moex-gov-tw", "moex": {"exam_code": "098090", "c": "501", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "098", "exam_name": "098年專技高考引水人、驗船師考試、普考地政士、專責報關人員、保險代理人經紀人及公證人考試、98年第一次消防設備士考試、98年特考中醫師考試", "original_question_number": 27, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02917', 'fire-eq-tech', 'fire-eq-tech-moex-098-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依照「各類場所消防安全設備設置標準」的規定，下列有關應設室外消防栓設備之規定敘述，何者有誤？', '["高度危險工作場所，其建築物及儲存面積在3000平方公尺以上者", "中度危險工作場所，其建築物及儲存面積在4000平方公尺以上者", "低度危險工作場所，其建築物及儲存面積在10000平方公尺以上者", "設有泡沫滅火設備者，在該有效範圍內，得免設"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:26+00:00", "source_pdf_sha1": "734519161faa", "answer_pdf_sha1": "253922401248", "source_family": "moex-gov-tw", "moex": {"exam_code": "098090", "c": "501", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "098", "exam_name": "098年專技高考引水人、驗船師考試、普考地政士、專責報關人員、保險代理人經紀人及公證人考試、98年第一次消防設備士考試、98年特考中醫師考試", "original_question_number": 28, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
